script.code:
if (focus == null) return null
def facName = basic.getExtensionPropertyValue(focus, new javax.xml.namespace.QName('urn:sciback:midpoint:person', 'facultyName'))
if (facName == null) return null
def name = facName.toString().trim()
if (!name) return null
// Switch nombre-de-facultad (ELISEO.ORG_AREA.NOMBRE) → authorised_value Bsort1 de Koha.
// Match exacto contra el nombre crudo Oracle. Facultades no listadas → null.
def bsort1Map = [
    'Facultad de Ciencias de la Salud'           : 'FCS',
    'Facultad de Ingeniería y Arquitectura'      : 'FIA',
    'Facultad de Ciencias Humanas y Educación'   : 'FACIHED',
    'Facultad de Ciencias Empresariales'         : 'FCE',
    'Facultad de Teología'                       : 'FACTEO',
    'Escuela General de Posgrado'                : 'EPG'
]
def result = bsort1Map.get(name)
if (result == null) {
    log.debug('statistics1-outbound: no Bsort1 mapping for facultyName "{}"', name)
}
return result

if (focus == null) return null
def pcode = basic.getExtensionPropertyValue(focus, new javax.xml.namespace.QName('urn:sciback:midpoint:person', 'academicProgramSuneduCode'))
if (pcode == null) return null
def code = pcode.toString().trim()
return code ? code : null

def aff = primaryAffiliation != null ? basic.stringify(primaryAffiliation).trim().toLowerCase() : '';
if (aff == '') return null;
if (aff == 'employee') return 'staff';
// vocabulario eduPerson 202208 literal: faculty/staff/student/alum/affiliate
if (aff == 'faculty' || aff == 'staff' || aff == 'student' || aff == 'alum' || aff == 'affiliate') return aff;
// cuentas sistema u otros → local (convención local explícita)
return 'local';

def out = [];
// par STUDY_LEVEL (solo students)
def aff = primaryAffiliation != null ? basic.stringify(primaryAffiliation).trim().toLowerCase() : '';
if (aff == 'student') {
    def level = studyLevel != null ? basic.stringify(studyLevel).trim().toLowerCase() : '';
    if (level == 'maestria' || level == 'doctorado' || level == 'segunda-especialidad' || level == 'especializacion' || level.contains('posgrado')) {
        out << '{"type":"STUDY_LEVEL","value":"posgrado"}';
    } else if (level == 'pregrado') {
        out << '{"type":"STUDY_LEVEL","value":"pregrado"}';
    } else {
        def cycles = (studentCycle instanceof Collection) ? studentCycle : (studentCycle != null ? [studentCycle] : []);
        def maxCycle = cycles.collect { it?.toString()?.trim()?.isInteger() ? it.toString().trim().toInteger() : -1 }.max();
        if (maxCycle != null && maxCycle >= 7) out << '{"type":"STUDY_LEVEL","value":"posgrado"}';
        else out << '{"type":"STUDY_LEVEL","value":"pregrado"}';
    }
}
// par DNI (para adopt-by-DNI del conector v1.3.10)
def dni = lambDocNum != null ? basic.stringify(lambDocNum).trim() : '';
if (dni ==~ /^\d{8}$/) out << '{"type":"DNI","value":"' + dni + '"}';
return out;

def campusMap = ['LIMA':'BUL', 'JULIACA':'BUJ', 'TARAPOTO':'BUT']
def cs = campusStudent?.toString()?.trim()?.toUpperCase()
def cw = campusWorker?.toString()?.trim()?.toUpperCase()
def loc = locality?.toString()?.trim()?.toUpperCase()
// Precedencia: campus vivo académico → campus vivo laboral → locality (fallback).
def effective = (cs != null && cs != '') ? cs : ((cw != null && cw != '') ? cw : (loc ?: ''))
// Mapa por campus; locality legacy CIA/ICA preservado; default conservador BUL.
['LIMA':'BUL', 'JULIACA':'BUJ', 'TARAPOTO':'BUT', 'CIA':'CIA', 'ICA':'CIA'].getOrDefault(effective, 'BUL')

// Expiry efectivo = MAX de las fechas de término reales por-IIA de las afiliaciones vivas.
def w = terminationDate?.toString()?.take(10)
def s = terminationDateStudent?.toString()?.take(10)
def realMax = null
if (w != null && s != null) { realMax = (w.compareTo(s) >= 0) ? w : s }
else if (w != null) { realMax = w }
else if (s != null) { realMax = s }

def today = java.time.LocalDate.now()

// FALLBACK (2026-06-02, tarea expiry): este mapping SOLO corre con afiliación viva
// (condition liveAffiliationWorker||liveAffiliationStudent). Casos sin fecha real futura:
//   (a) realMax == null  -> trabajador permanente FEC_TERMINO NULL (77 casos): nunca hubo fecha.
//   (b) realMax vencido  -> matrícula/contrato con fecha pasada pero afiliación AUN viva.
// En ambos, una afiliación VIVA no debe expirar la cuenta Koha. Computamos today + P12M.
// ANCLAJE canónico: liveAffiliation* ya retorna null cuando contrato/matrícula vence (IIA);
// al cesar, la condition false -> el mapping no participa -> el archivado leaver gana
// (DISABLED -> expiry=ayer). No sobre-extiende. eduPerson/SCHAC schacExpiryDate deriva del
// lifecycle desde la IIA (iga-canonical-standards §1.2).
if (realMax == null) {
    return today.plusMonths(12).toString()
}
def realMaxDate = java.time.LocalDate.parse(realMax)
if (realMaxDate.isBefore(today)) {
    return today.plusMonths(12).toString()
}
// Fecha real futura: comportamiento existente intacto (no se degrada).
return realMax

// ================================================================
// GATE KOHA MULTI-CAMPUS AFILIACIÓN-AWARE (tarea #65, 2026-06-03).
// Koha hoy = solo BUL (Lima). Elegible Koha-Lima si la persona tiene
// un VÍNCULO VIVO con Lima:
//   - matrícula vigente Lima  (campusStudent == 'LIMA'), O
//   - contrato 7124 vivo Lima (campusWorker  == 'LIMA').
// El EGRESO histórico de Lima NO cuenta (sin campusAlum en el gate):
// un egresado puro de Lima sin matrícula/contrato vivo NO es elegible.
// Provincia pura (Juliaca/Tarapoto/ISTAT, sin vínculo vivo Lima) → excluido.
//
// campusStudent/campusWorker son slots per-IIA single-valued single-writer
// (Estudiantes/Trabajadores) poblados strong single-source — misma vigencia
// VIVA que liveAffiliationStudent/Worker. locality NO entra al gate (queda
// libre para LDAP/Entra/M365, semántica de lugar físico).
//
// FUSIÓN 4 KOHA (mitad de año): cuando BUJ/BUT/BU-ISTAT entren a este IGA,
// quitar la condición `&& hasLimaAffiliation` (1 línea) → vuelve a ser
// gate puro por afiliación viva multi-campus. Diseñado para ese cambio.
// ================================================================
def worker  = liveAffiliationWorker
def student = liveAffiliationStudent
def guest   = smartwifiGuest
def hasLib  = focus?.roleMembershipRef?.any { it?.oid == '91b2cbcd-3db9-4e90-b72e-b874b3c48fa6' }
// hasLiveAff: tiene algún vínculo vivo elegible (worker|student|guest|bibliotecario).
def hasLiveAff = (worker != null) || (student != null) || (guest != null) || hasLib
// hasLimaAffiliation: el vínculo VIVO es con Lima (matrícula O contrato Lima).
// guest (visita Smart WiFi campus Lima) y hasLib (bibliotecario BUL) son
// vínculos Lima por naturaleza hoy → cuentan como Lima.
def cs = (campusStudent ?: '').toString().trim().toUpperCase()
def cw = (campusWorker  ?: '').toString().trim().toUpperCase()
def hasLimaAffiliation = (cs == 'LIMA') || (cw == 'LIMA') || (guest != null) || hasLib
def eligible = hasLiveAff && hasLimaAffiliation
// suma-nunca-resta: si el patrón Koha YA EXISTE (reality), NUNCA borrar.
// Se archiva vía administrativeStatus=disabled (expiry+card_lost), jamás delete.
// El deprovisioning de provincia (Juliaca/Tarapoto) se hace por bulk unlink +
// archivado koha-expert fuera de este mapping; aquí solo gobernamos creación
// y preservación (no confiamos el delete a este gate).
//
// BLINDAJE ANTI-DELETE (Fase 2.5, 2026-06-04).
// La barrera DURA contra el borrado es la capability `delete` DESHABILITADA
// (bloque <configured> al final del resource): Koha NUNCA recibe un DELETE de
// patrón, pase lo que pase con este mapping. Por eso aquí NO replicamos lógica
// de query frágil (un error de script abortaría el existence en CADA recompute
// de CADA foco — peor que el problema). Guard simple y defensivo:
// BLINDAJE getLinkedShadow (tarea #65, caso Tito 43508613): si el foco tiene un
// shadow huérfano/dangling, getLinkedShadow puede lanzar; con try/catch→null no
// abortamos el mapping ni afirmamos existencia falsa.
//
// Caso 22422 (runbook §4): durante un recon que crea+linkea en el MISMO
// clockwork, getLinkedShadow aún devuelve null para un foco inelegible → este
// mapping retorna false. ANTES eso disparaba DELETE; AHORA la capability delete
// deshabilitada lo intercepta → 0 borrado. El deprovisioning real del leaver lo
// hace administrativeStatus=DISABLED (expiry+card_lost), archivado graceful.
def existing = null
try {
    existing = midpoint.getLinkedShadow(focus, '9b5a7c81-47aa-42ac-9a08-4de8b64935af')
} catch (Exception e) {
    log.warn('koha-account-existence: getLinkedShadow falló para {} → existing=null: {}', focus?.name, e.message)
    existing = null
}
// Decisión final. Aunque retorne false para un inelegible-sin-shadow (caso
// legítimo: NO crear), el DELETE está bloqueado por capability → 0 riesgo de
// borrado. midpoint-best-practices §7 (existence defensivo).
return eligible || (existing != null)

import groovy.json.JsonSlurper
def vals = basic.getAttributeValues(projection, 'extended_attributes')
if (vals != null) {
    def slurper = new JsonSlurper()
    for (v in vals) {
        if (v == null) continue
        try {
            def o = slurper.parseText(v.toString())
            if (o?.type == 'DNI' && o?.value != null) {
                def dni = o.value.toString().trim()
                if (dni ==~ /^\d{8}$/) return dni
            }
        } catch (ignored) {}
    }
}
return '__NO_MATCH__'
